import { MakeLogicType, actions, afterMount, connect, kea, key, path, props } from 'kea'
import { loaders } from 'kea-loaders'

import { teamLogic } from 'scenes/teamLogic'

import { logsAlertsEventsList } from 'products/logs/frontend/generated/api'
import { LogsAlertEventApi } from 'products/logs/frontend/generated/api.schemas'


export interface LogsAlertEventHistoryLogicProps {
    alertId: string
}

export interface EventsPage {
    results: LogsAlertEventApi[]
    next: string | null
    count: number
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logsAlertEventHistoryLogicValues {
    currentTeamId: number | null; // teamLogic
    eventsPage: EventsPage;
    eventsPageLoading: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logsAlertEventHistoryLogicActions {
    loadEvents: () => any;
    loadEventsFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadEventsSuccess: (eventsPage: {
        count: number;
        next: string | null;
        results: LogsAlertEventApi[];
    }, payload?: any) => {
        eventsPage: {
            count: number;
            next: string | null;
            results: LogsAlertEventApi[];
        };
        payload?: any;
    };
    loadMore: () => {
        value: true;
    };
    loadMoreFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadMoreSuccess: (eventsPage: EventsPage, payload?: {
        value: true;
    }) => {
        eventsPage: EventsPage;
        payload?: {
            value: true;
        };
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logsAlertEventHistoryLogicMeta {
    key: string;
}

export type logsAlertEventHistoryLogicType = MakeLogicType<logsAlertEventHistoryLogicValues, logsAlertEventHistoryLogicActions, LogsAlertEventHistoryLogicProps, logsAlertEventHistoryLogicMeta>;

export const logsAlertEventHistoryLogic = kea<logsAlertEventHistoryLogicType>([
    path((key) => ['products', 'logs', 'frontend', 'components', 'LogsAlerting', 'logsAlertEventHistoryLogic', key]),
    props({} as LogsAlertEventHistoryLogicProps),
    key((props) => props.alertId),

    connect({
        values: [teamLogic, ['currentTeamId']],
    }),

    actions({
        loadMore: true,
    }),

    loaders(({ props, values }) => ({
        eventsPage: [
            { results: [], next: null, count: 0 } as EventsPage,
            {
                loadEvents: async () => {
                    const projectId = String(values.currentTeamId)
                    const response = await logsAlertsEventsList(projectId, props.alertId)
                    return {
                        results: response.results ?? [],
                        next: response.next ?? null,
                        count: response.count ?? 0,
                    }
                },
                loadMore: async () => {
                    const nextUrl = values.eventsPage.next
                    if (!nextUrl) {
                        return values.eventsPage
                    }
                    const res = await fetch(nextUrl, { credentials: 'include' })
                    if (!res.ok) {
                        throw new Error(`Failed to load more events: ${res.status} ${res.statusText}`)
                    }
                    const data = (await res.json()) as {
                        results?: LogsAlertEventApi[]
                        next?: string | null
                        count?: number
                    }
                    return {
                        results: [...values.eventsPage.results, ...(data.results ?? [])],
                        next: data.next ?? null,
                        count: data.count ?? values.eventsPage.count,
                    }
                },
            },
        ],
    })),

    afterMount(({ actions }) => {
        actions.loadEvents()
    }),
])
